Read this component. What can you tell about the page structure without seeing any child component's code?

```jsx
import Breadcrumb from "./Breadcrumb";
import ProductImage from "./ProductImage";
import ProductInfo from "./ProductInfo";
import AddToCartButton from "./AddToCartButton";
import ReviewList from "./ReviewList";

function ProductPage() {
  const product = {
    name: "Ergonomic Keyboard",
    price: 129.99,
    rating: 4.5,
  };

  return (
    <>
      <Breadcrumb current={product.name} />
      <div className="product-layout">
        <ProductImage />
        <div className="product-details">
          <ProductInfo name={product.name} price={product.price} />
          <AddToCartButton price={product.price} />
        </div>
      </div>
      <ReviewList rating={product.rating} />
    </>
  );
}
```

